 1→import dayjs from 'dayjs';
 2→
 3→import { IAnnouncementItem } from '@/types/announcement.ts';
 4→import { objectPick } from '@/utils/object.ts';
 5→
 6→export const toAnnounce = (v?: unknown): IAnnouncementItem => {
 7→  const time = objectPick(v, 'publishTime', '');
 8→  return {
 9→    announceId: objectPick(v, 'id', ''),
10→    content: objectPick(v, 'content', ''),
11→    title: objectPick(v, 'title', ''),
12→    publishTime: time ? dayjs(time).format('YYYY-MM-DD HH:mm') : '',
13→    autoPopout: objectPick(v, 'isPopup', false),
14→  };
15→};
16→
17→export const announceTo = (v: IAnnouncementItem) => {
18→  return {
19→    title: v.title,
20→    content: v.content,
21→    isPopup: v.autoPopout,
22→    publishTime: dayjs(v.publishTime).format('YYYY-MM-DD HH:mm:ss'),
23→    announcementId: v.announceId,
24→  };
25→};
