  1→import { Button, DatePicker, Dropdown, Modal } from 'antd';
  2→import dayjs from 'dayjs';
  3→import type { FC, PropsWithChildren, Ref } from 'react';
  4→import { memo, useCallback, useImperativeHandle, useState } from 'react';
  5→
  6→import { toAnnounce } from '@/common/dataConversion/announce.ts';
  7→import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
  8→import { TipTapEditor } from '@/components/Common/TiptapEditor/TipTapEditor.tsx';
  9→import type { IEditorTool } from '@/components/Common/TiptapEditor/type';
 10→import { FontColor } from '@/components/icon/FontColor';
 11→import { t } from '@/i18n';
 12→import type { IAnnouncementItem } from '@/types/announcement.ts';
 13→
 14→export type IModifyAnnounceInstance = {
 15→  show(v?: IAnnouncementItem): void;
 16→  close(): void;
 17→};
 18→
 19→const ModifyAnnouncementBase: FC<PropsWithChildren<{
 20→  onOk?(v: IAnnouncementItem): void;
 21→  confirmLoading?: boolean;
 22→  ref?: Ref<IModifyAnnounceInstance>;
 23→}>> = ({
 24→  children, ref, confirmLoading, onOk,
 25→}) => {
 26→  const [open, setOpen] = useState(false);
 27→  const [inEditingData, setInEditingData] = useState<IAnnouncementItem>(() => toAnnounce());
 28→  useImperativeHandle(ref, () => {
 29→    return {
 30→      close() {
 31→        setOpen(false);
 32→      },
 33→      show(v) {
 34→        setInEditingData(v
 35→          ? v
 36→          : toAnnounce());
 37→        setOpen(true);
 38→      },
 39→    };
 40→  });
 41→
 42→  // 移除knock不支持的文字样式，文字颜色只支持黑（重置）红绿
 43→  const modifyEditorTools = useCallback<NonNullable<Parameters<typeof TipTapEditor>[0]['modifyTools']>>((tools, { editor }) => {
 44→    const result: IEditorTool[] = [];
 45→    for (const tool of tools) {
 46→      if (tool.name === 'textBg' || tool.name === 'underline') {
 47→        continue;
 48→      }
 49→      if (tool.name === 'fontColor') {
 50→        const { color } = editor.getAttributes('textStyle');
 51→        result.push({
 52→          name: 'fontColor',
 53→          node: (
 54→            <Dropdown
 55→              trigger={['click']}
 56→              menu={{
 57→                items: [
 58→                  {
 59→                    key: 'unset',
 60→                    label: <>{t('reset')}</>,
 61→                  },
 62→                  {
 63→                    key: '#dd191d',
 64→                    label: <span style={{ color: '#dd191d' }}>{t('red')}</span>,
 65→                  },
 66→                  {
 67→                    key: '#3ca51e',
 68→                    label: <span style={{ color: '#3ca51e' }}>{t('green')}</span>,
 69→                  },
 70→                ],
 71→                onClick: ({ key }) => {
 72→                  if (key === 'unset') {
 73→                    editor.commands.unsetColor();
 74→                  } else {
 75→                    editor.commands.setColor(key);
 76→                  }
 77→                },
 78→              }}
 79→            >
 80→              <Button
 81→                size="small"
 82→                icon={<FontColor style={{ color }} className="text-[16px]" />}
 83→                variant={color ? 'filled' : 'text'}
 84→                color={color ? 'primary' : 'default'}
 85→              />
 86→            </Dropdown>
 87→          ),
 88→        });
 89→        continue;
 90→      }
 91→      result.push(tool);
 92→    }
 93→    return result;
 94→  }, []);
 95→  return (
 96→    <>
 97→      <Modal
 98→        mask={{ closable: false }}
 99→        onCancel={() => setOpen(false)}
100→        open={open}
101→        destroyOnHidden
102→        width={650}
103→        onOk={() => onOk?.(inEditingData)}
104→        confirmLoading={confirmLoading}
105→        title={<I18nText>upgradeConfig</I18nText>}
106→      >
107→        <div className="mb-2">
108→          <span className="mr-4">
109→            <I18nText>publishTime</I18nText>
110→          </span>
111→          <DatePicker
112→            format="YYYY-MM-DD HH:mm"
113→            showTime={{
114→              format: 'HH:mm',
115→              showSecond: false,
116→            }}
117→            value={inEditingData.publishTime ? dayjs(inEditingData.publishTime) : undefined}
118→            onChange={(_e, date) => {
119→              setInEditingData({
120→                ...inEditingData,
121→                publishTime: date as string,
122→              });
123→            }}
124→          />
125→        </div>
126→        <div className="mb-1">
127→          <I18nText>announceContent</I18nText>
128→        </div>
129→        <TipTapEditor
130→          value={inEditingData.content}
131→          onChange={(e) => {
132→            setInEditingData({
133→              ...inEditingData,
134→              content: e,
135→            });
136→          }}
137→          modifyTools={modifyEditorTools}
138→          editable
139→          className="max-h-[450px] mb-2"
140→        />
141→      </Modal>
142→      <span onClick={() => setOpen(true)}>
143→        {children}
144→      </span>
145→
146→    </>
147→  );
148→};
149→export const ModifyAnnouncement = memo(ModifyAnnouncementBase);
